import React, { useRef, useEffect, useState } from 'react';

function Graph({ results, currentR, onCanvasClick }) {
  const canvasRef = useRef(null);
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  // Отслеживаем изменение ширины окна
  useEffect(() => {
    const handleResize = () => setWindowWidth(window.innerWidth);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Динамический масштаб
  const getScale = () => {
    if (windowWidth < 728) return 30; // Мобильный
    return 40; // Десктоп/планшет
  };

  const getCenter = () => {
    if (windowWidth < 728) return 150; // Мобильный
    return 200; // Десктоп/планшет
  };

  // Отрисовка графика при изменении данных или размеров окна
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    const SCALE = getScale();
    const CENTER = getCenter();

    // Очистка канваса
    ctx.clearRect(0, 0, 400, 400);

    // Рисуем оси
    drawAxes(ctx, SCALE, CENTER);

    // Рисуем область для текущего R
    if (currentR) {
      drawShapes(ctx, currentR, SCALE, CENTER);
    }

    // Рисуем все точки
    results.forEach(point => {
      drawPoint(ctx, point, SCALE, CENTER, windowWidth, currentR, results);
    });
  }, [results, currentR, windowWidth]);

  const handleClick = (e) => {
    if (!currentR) {
      alert('Сначала выберите радиус R для проверки точки');
      return;
    }

    const canvas = canvasRef.current;
    if (!canvas) return;

    const rect = canvas.getBoundingClientRect();
    const SCALE = getScale();
    const CENTER = getCenter();

    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const graphX = (x - CENTER) / SCALE;
    const graphY = (CENTER - y) / SCALE;

    const roundedX = Math.round(graphX * 100) / 100;
    const roundedY = Math.round(graphY * 100) / 100;

    onCanvasClick(roundedX, roundedY);
  };

  const drawAxes = (ctx, SCALE, CENTER) => {
    ctx.strokeStyle = '#2c3e50';
    ctx.lineWidth = 1;
    ctx.fillStyle = '#2c3e50';

    // Ось X
    ctx.beginPath();
    ctx.moveTo(0, CENTER);
    ctx.lineTo(400, CENTER);
    ctx.stroke();

    // Ось Y
    ctx.beginPath();
    ctx.moveTo(CENTER, 0);
    ctx.lineTo(CENTER, 400);
    ctx.stroke();

    // Стрелки
    ctx.beginPath();
    ctx.moveTo(390, CENTER - 5);
    ctx.lineTo(400, CENTER);
    ctx.lineTo(390, CENTER + 5);
    ctx.fill();

    ctx.beginPath();
    ctx.moveTo(CENTER - 5, 10);
    ctx.lineTo(CENTER, 0);
    ctx.lineTo(CENTER + 5, 10);
    ctx.fill();

    // Разметка осей
    ctx.font = '12px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';

    // Деления по оси X
    for (let i = -5; i <= 5; i++) {
      if (i !== 0) {
        const x = CENTER + i * SCALE;
        ctx.beginPath();
        ctx.moveTo(x, CENTER - 5);
        ctx.lineTo(x, CENTER + 5);
        ctx.stroke();
        ctx.fillText(i.toString(), x, CENTER + 10);
      }
    }

    // Деления по оси Y
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';
    for (let i = -5; i <= 5; i++) {
      if (i !== 0) {
        const y = CENTER - i * SCALE;
        ctx.beginPath();
        ctx.moveTo(CENTER - 5, y);
        ctx.lineTo(CENTER + 5, y);
        ctx.stroke();
        ctx.fillText(i.toString(), CENTER - 10, y);
      }
    }

    // Подписи осей
    ctx.fillStyle = '#2c3e50';
    ctx.font = '14px Arial';
    ctx.textAlign = 'right';
    ctx.fillText('Y', CENTER - 10, 20);
    ctx.textAlign = 'left';
    ctx.fillText('X', 390, CENTER - 10);
  };

  const drawShapes = (ctx, r, SCALE, CENTER) => {
  if (!r || r <= 0) {
      return; // Просто не рисуем область
    }
    const scaleR = r * SCALE;
    const scaleRHalf = (r / 2) * SCALE;

    ctx.fillStyle = 'rgba(52, 152, 219, 0.4)';
    ctx.strokeStyle = '#3498db';
    ctx.lineWidth = 2;

    // 1. Часть круга в 1-й четверти (радиус R/2)
    ctx.beginPath();
    ctx.arc(CENTER, CENTER, scaleRHalf, -Math.PI / 2, 0, false);
    ctx.lineTo(CENTER, CENTER);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // 2. Треугольник во 2-й четверти: (0,0), (-R,0), (0,R)
    ctx.beginPath();
    ctx.moveTo(CENTER, CENTER); // (0,0)
    ctx.lineTo(CENTER - scaleR, CENTER); // (-R,0)
    ctx.lineTo(CENTER, CENTER - scaleR); // (0,R)
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // 3. Прямоугольник в 3-й четверти: (0,0), (-R/2,0), (0,-R), (-R/2,-R)
    ctx.beginPath();
    ctx.rect(CENTER - scaleRHalf, CENTER, scaleRHalf, scaleR);
    ctx.fill();
    ctx.stroke();
  };

  const drawPoint = (ctx, point, SCALE, CENTER, windowWidth, currentR, results) => {
    const pointX = CENTER + point.x * SCALE;
    const pointY = CENTER - point.y * SCALE;

    // Выбираем цвет точки в зависимости от результата и актуальности R
    let color;
    if (currentR && point.r === currentR) {
      // Точки с текущим R
      color = point.hit ? '#27ae60' : '#e74c3c'; // Зеленый для попадания, красный для промаха
    } else {
      // Точки с другими R
      color = point.hit ? 'rgba(39, 174, 96, 0.5)' : 'rgba(231, 76, 60, 0.5)';
    }

    // Определяем размер точки
    const radius = (windowWidth < 728) ? 3 : (currentR && point.r === currentR ? 6 : 4);

    // Рисуем точку
    ctx.beginPath();
    ctx.arc(pointX, pointY, radius, 0, Math.PI * 2);
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = '#2c3e50';
    ctx.lineWidth = 1;
    ctx.stroke();
  };

  return (
    <div className="graph-container">
      <h3>Область проверки {currentR ? `(R = ${currentR})` : ''}</h3>
      <canvas
        ref={canvasRef}
        width="400"
        height="400"
        onClick={handleClick}
        className="area-canvas"
        style={{ cursor: currentR ? 'crosshair' : 'not-allowed' }}
      />
      <p className="graph-hint">
        {currentR
          ? 'Кликните на график для проверки точки с текущим R'
          : 'Выберите радиус R для проверки точки'}
      </p>
      <div className="legend">
        <div className="legend-item">
          <div className="legend-color" style={{ backgroundColor: '#27ae60' }}></div>
          <span>Попадание (текущий R)</span>
        </div>
        <div className="legend-item">
          <div className="legend-color" style={{ backgroundColor: '#e74c3c' }}></div>
          <span>Промах (текущий R)</span>
        </div>
        <div className="legend-item">
          <div className="legend-color" style={{ backgroundColor: 'rgba(39, 174, 96, 0.5)' }}></div>
          <span>Попадание (другой R)</span>
        </div>
        <div className="legend-item">
          <div className="legend-color" style={{ backgroundColor: 'rgba(231, 76, 60, 0.5)' }}></div>
          <span>Промах (другой R)</span>
        </div>
      </div>
    </div>
  );
}

export default Graph;
